#!/bin/bash

# Samuel.ai Server Setup Script
# Run as root or user with sudo

# 1. Update & Basic Tools
echo "$SUDO_PASS" | sudo -S apt-get update
echo "$SUDO_PASS" | sudo -S apt-get install -y git curl unzip zip nginx supervisor supervisor sqlite3 libcap2-bin software-properties-common

# 2. Add PHP 8.3 Repository
echo "$SUDO_PASS" | sudo -S add-apt-repository -y ppa:ondrej/php
echo "$SUDO_PASS" | sudo -S apt-get update

# 3. Install PHP 8.3 & Extensions
echo "$SUDO_PASS" | sudo -S apt-get install -y php8.3-fpm php8.3-cli php8.3-mongodb php8.3-curl php8.3-mbstring php8.3-xml php8.3-zip php8.3-bcmath php8.3-intl php8.3-readline php8.3-redis php8.3-mysql php8.3-sqlite3

# 4. Install Composer
curl -sS https://getcomposer.org/installer | php
echo "$SUDO_PASS" | sudo -S mv composer.phar /usr/local/bin/composer

# 5. Install Node.js & NPM
curl -fsSL https://deb.nodesource.com/setup_20.x | echo "$SUDO_PASS" | sudo -E -S bash -
echo "$SUDO_PASS" | sudo -S apt-get install -y nodejs

# 6. Install Redis
echo "$SUDO_PASS" | sudo -S apt-get install -y redis-server
echo "$SUDO_PASS" | sudo -S systemctl enable redis-server

# 7. Setup Web Directory
echo "$SUDO_PASS" | sudo -S mkdir -p /var/www/bibleai
echo "$SUDO_PASS" | sudo -S chown -R $USER:$USER /var/www/bibleai
echo "$SUDO_PASS" | sudo -S chmod -R 755 /var/www/bibleai

# 8. Setup SSH Key (Add the public key generated by the agent)
mkdir -p ~/.ssh
echo "ssh-rsa  anto@anto" >> ~/.ssh/authorized_keys
chmod 700 ~/.ssh
chmod 600 ~/.ssh/authorized_keys

# 9. Clone Repository (Initial)
if [ ! -d "/var/www/bibleai/.git" ]; then
    git clone https://github.com/AntonyMN/bible-ai-samuel.git /var/www/bibleai
fi

# 10. Install MongoDB
echo "$SUDO_PASS" | sudo -S apt-get install -y gnupg wget
wget -qO - https://www.mongodb.org/static/pgp/server-7.0.asc | printf "%s\n" "$SUDO_PASS" | sudo -S gpg --dearmor | printf "%s\n" "$SUDO_PASS" | sudo -S tee /usr/share/keyrings/mongodb-server-7.0.gpg > /dev/null
echo "deb [ arch=amd64,arm64 signed-by=/usr/share/keyrings/mongodb-server-7.0.gpg ] https://repo.mongodb.org/apt/ubuntu jammy/mongodb-org/7.0 multiverse" | printf "%s\n" "$SUDO_PASS" | sudo -S tee /etc/apt/sources.list.d/mongodb-org-7.0.list
echo "$SUDO_PASS" | sudo -S apt-get update
echo "$SUDO_PASS" | sudo -S apt-get install -y mongodb-org
echo "$SUDO_PASS" | sudo -S systemctl start mongod
echo "$SUDO_PASS" | sudo -S systemctl enable mongod

echo "Server Setup Phase 1 Complete. Please configure NGINX next."
